const item = firstItem.json;

const amazonPrice = item.amazon?.price || 0; 
const aliexpressPrice = item.minPrice || 0;

const shippingCost = aliexpressPrice * 0.15;

const totalCost = aliexpressPrice + shippingCost;

const minMargin = 30; 

let suggestedPrice = totalCost + minMargin;

let margin = suggestedPrice - totalCost;

let canUndercutAmazon = false;

if (amazonPrice > 0) {
  if (suggestedPrice < amazonPrice) {
    canUndercutAmazon = true;
  } else {
    const maxPossiblePrice = amazonPrice - 0.01; // Undercut by 1 c
    const potentialMargin = maxPossiblePrice - totalCost;

    if (potentialMargin >= minMargin) {
      suggestedPrice = maxPossiblePrice;
      margin = potentialMargin;
      canUndercutAmazon = true;
    }
  }
}

const passesProfitMargin = margin >= minMargin;

const profitPercentage = totalCost > 0 ? ((margin / totalCost) * 100).toFixed(2) : 0;

return [{
  json: {
    ...item,
    pricing: {
      aliexpress_price: parseFloat(aliexpressPrice.toFixed(2)),
      amazon_price: parseFloat(amazonPrice.toFixed(2)),
      shipping_cost: parseFloat(shippingCost.toFixed(2)),
      total_cost: parseFloat(totalCost.toFixed(2)),
      suggested_price: parseFloat(suggestedPrice.toFixed(2)),
