import json
import re
from datetime import datetime

def transform_list_to_string(value):
    if isinstance(value, list):
        if len(value) == 0:
            return ""
        elif len(value) == 1:
            return value[0]
        else:
            return "; ".join(value)
    return value

def parse_price_field(price_value):
    """Parse price field that might be a JSON object or string"""
    if isinstance(price_value, dict):
        if 'min_price' in price_value:
            return price_value['min_price']
        elif 'min_price_value' in price_value:
            return price_value['min_price_value']
        elif 'price' in price_value:
            return price_value['price']
        else:
            return str(price_value)
    elif isinstance(price_value, str):
        try:
            # Try to parse as JSON string
            price_data = json.loads(price_value)
            if isinstance(price_data, dict):
                if 'min_price' in price_data:
                    return price_data['min_price']
                elif 'min_price_value' in price_data:
                    return price_data['min_price_value']
                elif 'price' in price_data:
                    return price_data['price']
            return price_value
        except (json.JSONDecodeError, TypeError):
            return price_value
    return price_value

def clean_field_value(value):
    """Clean field values that might contain complex objects"""
    if isinstance(value, dict):
        if any(key in value for key in ['min_price', 'max_price', 'price']):
            return parse_price_field(value)
        return str(value)
    elif isinstance(value, str):
        if value.strip().startswith('{') and value.strip().endswith('}'):
            try:
                parsed = json.loads(value)
                if isinstance(parsed, dict) and any(key in parsed for key in ['min_price', 'max_price', 'price']):
                    return parse_price_field(value)
                return str(parsed)
            except json.JSONDecodeError:
                pass
    return value

now = datetime.now()
current_datetime = now.strftime("%m/%d/%Y, %I:%M:%S %p")

for item in _input.all():
    output_text = item.json.get('output', '')

    json_match = re.search(r'```json\n(.*?)\n```', output_text, re.DOTALL)

    if json_match:
        json_string = json_match.group(1)
        try:
            parsed_json = json.loads(json_string)

            if isinstance(parsed_json, dict):
                transformed_data = {}
                for key, value in parsed_json.items():
                    cleaned_value = clean_field_value(value)
                    transformed_data[key] = transform_list_to_string(cleaned_value)

                price_fields = ['SELLING PRICE', 'TikTok Price', 'AMAZON PRICE', 'ALIEXPRESS PRICE', 'Alibaba Price', 'Temu Price']
                for price_field in price_fields:
                    if price_field in transformed_data:
                        original_value = parsed_json[price_field]
                        if isinstance(original_value, dict) and 'min_price' in original_value:
                            transformed_data[price_field] = original_value['min_price']
                        elif original_value != "None":
                            transformed_data[price_field] = parse_price_field(original_value)

                item.json = transformed_data
                item.json['today'] = current_datetime

            elif isinstance(parsed_json, list):
                if len(parsed_json) > 0 and isinstance(parsed_json[0], dict):
                    first_object = parsed_json[0]
                    transformed_data = {}
                    for key, value in first_object.items():
                        cleaned_value = clean_field_value(value)
                        transformed_data[key] = transform_list_to_string(cleaned_value)

                    price_fields = ['SELLING PRICE', 'TikTok Price', 'AMAZON PRICE', 'ALIEXPRESS PRICE', 'Alibaba Price', 'Temu Price']
                    for price_field in price_fields:
                        if price_field in transformed_data:
                            original_value = first_object[price_field]
                            if isinstance(original_value, dict) and 'min_price' in original_value:
                                transformed_data[price_field] = original_value['min_price']
                            elif original_value != "None":
                                transformed_data[price_field] = parse_price_field(original_value)

                    item.json = transformed_data
                    item.json['today'] = current_datetime
                else:
                    cleaned_data = clean_field_value(parsed_json)
                    item.json = {
                        'data': transform_list_to_string(cleaned_data),
                        'today': current_datetime
                    }
            else:
                item.json = {
                    'data': str(parsed_json),
                    'today': current_datetime
                }

        except json.JSONDecodeError as e:
            item.json['parsed_json'] = None
            item.json['parse_error'] = str(e)
            item.json['today'] = current_datetime
    else:
        item.json['parsed_json'] = None
        item.json['parse_error'] = 'No JSON code block found'
        item.json['today'] = current_datetime

return _input.all()

